from transformers import pipeline as hf_pipeline
import torch

# Safety checker: screen outputs before returning to users
safety_checker = hf_pipeline(
    "image-classification",
    model="Falconsai/nsfw_image_detection",
    device="cuda",
)

def safe_generate(pipe, prompt: str, **kwargs) -> dict:
    """Generate an image with safety filtering."""
    result = pipe(prompt=prompt, **kwargs)
    image = result.images[0]

    # Check for unsafe content
    safety_result = safety_checker(image)
    labels = {r["label"]: r["score"] for r in safety_result}

    if labels.get("nsfw", 0) > 0.5:
        return {"image": None, "blocked": True, "reason": "unsafe_content"}

    return {"image": image, "blocked": False}

# Prompt length check: CLIP tokenises to max 77 tokens
def check_prompt_length(tokenizer, prompt: str) -> int:
    """Return number of tokens; warn if truncation will occur."""
    tokens = tokenizer.encode(prompt)
    if len(tokens) > 77:
        import warnings
        warnings.warn(
            f"Prompt has {len(tokens)} tokens but CLIP truncates at 77. "
            f"Last {len(tokens) - 77} tokens will be ignored.",
            UserWarning,
        )
    return len(tokens)
